import { useEffect, useState } from "react";
import api from "../api";

export default function Customers() {
    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(0);
    const size = 10;
    const [totalPages, setTotalPages] = useState(1);

    useEffect(() => { load(); }, [page]);

    async function load() {
        setLoading(true);
        try {
            const res = await api.get("/api/customers", { params: { page, size }});
            const data = res.data || {};
            const content = Array.isArray(data) ? data : (data.content || []);
            setRows(content);
            setTotalPages((Array.isArray(data) ? 1 : (data.totalPages ?? 1)) || 1);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    return (
        <div className="p-6">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold">👥 Khách hàng</h2>
                <div className="text-sm text-slate-600">Trang {page+1}/{totalPages}</div>
            </div>

            {loading ? <p>Đang tải...</p> : (
                <>
                    <div className="overflow-auto">
                        <table className="min-w-full border text-sm">
                            <thead className="bg-gray-100">
                            <tr>
                                <th className="border p-2">Tên</th>
                                <th className="border p-2">Nhóm</th>
                                <th className="border p-2">Khu vực</th>
                                <th className="border p-2">Địa chỉ</th>
                                <th className="border p-2">Liên hệ</th>
                                <th className="border p-2">Điện thoại</th>
                                <th className="border p-2">Email</th>
                            </tr>
                            </thead>
                            <tbody>
                            {rows.map(c => (
                                <tr key={c.id}>
                                    <td className="border p-2">{c.name}</td>
                                    <td className="border p-2">{c.customerGroup}</td>
                                    <td className="border p-2">{c.region}</td>
                                    <td className="border p-2">{c.address}</td>
                                    <td className="border p-2">{c.contactPerson || "-"}</td>
                                    <td className="border p-2">{c.phone}</td>
                                    <td className="border p-2">{c.email}</td>
                                </tr>
                            ))}
                            </tbody>
                        </table>
                    </div>

                    <div className="flex gap-2 mt-3">
                        <button disabled={page<=0}
                                onClick={()=>setPage(p=>Math.max(0, p-1))}
                                className="px-3 py-1 rounded bg-slate-100 disabled:opacity-50">
                            ← Trước
                        </button>
                        <button disabled={page+1>=totalPages}
                                onClick={()=>setPage(p=>p+1)}
                                className="px-3 py-1 rounded bg-slate-100 disabled:opacity-50">
                            Sau →
                        </button>
                    </div>
                </>
            )}
        </div>
    );
}
